a.code:
/* Fight with specificity */
.card.card.card {
  padding: 1rem;
}

/* Or the nuclear option */
.card {
  padding: 1rem !important;
}

b.code:
@layer base, components, overrides;

@layer base {
  .card { padding: 2rem; }
}

@layer overrides {
  .card { padding: 1rem; }
  /* Always wins. No !important */
}

slides.code:
/* Declare layer order */
@layer framework, app;

/* Import Tailwind into a layer */
@import url('tailwind.css') layer(framework);

/* Your CSS always wins */
@layer app {
  .btn {
    /* Beats Tailwind automatically */
    /* No !important needed */
    border-radius: 0;
  }
}
